import sys
from collections import defaultdict, deque
from typing import List

class Solution:
    def kosaraju(self, V: int, edges: List[List[int]]) -> List[List[int]]:
        graph = defaultdict(list)
        for u, v in edges:
            graph[u].append(v)

        visited = [False] * V
        stack = []
        for i in range(V):
            if not visited[i]:
                self.dfs(graph, i, visited, stack)

        transpose_graph = self.transpose(graph, V)
        visited = [False] * V
        sccs = []
        while stack:
            vertex = stack.pop()
            if not visited[vertex]:
                scc = []
                self.dfs(transpose_graph, vertex, visited, scc)
                sccs.append(scc)

        return sccs

    def dfs(self, graph, vertex, visited, stack):
        visited[vertex] = True
        for neighbor in graph[vertex]:
            if not visited[neighbor]:
                self.dfs(graph, neighbor, visited, stack)
        stack.append(vertex)

    def transpose(self, graph, V):
        transpose_graph = defaultdict(list)
        for u in range(V):
            for v in graph[u]:
                transpose_graph[v].append(u)
        return transpose_graph

if __name__ == '__main__':
    it = iter(sys.stdin.read().split())
    try:
        V, E = map(int, (next(it), next(it)))
        edges = [[int(next(it)), int(next(it))] for _ in range(E)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    sccs = sol.kosaraju(V, edges)
    for scc in sccs:
        print(' '.join(map(str, scc)))

