#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> kosaraju(int V, vector<vector<int>>& edges) {
        vector<vector<int>> graph(V);
        for (const auto& edge : edges) {
            graph[edge[0]].push_back(edge[1]);
        }

        vector<bool> visited(V, false);
        vector<int> stack;
        for (int i = 0; i < V; ++i) {
            if (!visited[i]) {
                dfs(graph, i, visited, stack);
            }
        }

        vector<vector<int>> transpose_graph = transpose(graph, V);
        visited.assign(V, false);
        vector<vector<int>> sccs;
        while (!stack.empty()) {
            int vertex = stack.back();
            stack.pop_back();
            if (!visited[vertex]) {
                vector<int> scc;
                dfs(transpose_graph, vertex, visited, scc);
                sccs.push_back(scc);
            }
        }

        return sccs;
    }

private:
    void dfs(const vector<vector<int>>& graph, int vertex, vector<bool>& visited, vector<int>& stack) {
        visited[vertex] = true;
        for (int neighbor : graph[vertex]) {
            if (!visited[neighbor]) {
                dfs(graph, neighbor, visited, stack);
            }
        }
        stack.push_back(vertex);
    }

    vector<vector<int>> transpose(const vector<vector<int>>& graph, int V) {
        vector<vector<int>> transpose_graph(V);
        for (int u = 0; u < V; ++u) {
            for (int v : graph[u]) {
                transpose_graph[v].push_back(u);
            }
        }
        return transpose_graph;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int V, E;
    if (!(cin >> V >> E)) return 0;
    vector<vector<int>> edges(E, vector<int>(2));
    for (int i = 0; i < E; ++i) {
        if (!(cin >> edges[i][0] >> edges[i][1])) return 0;
    }
    Solution sol;
    vector<vector<int>> sccs = sol.kosaraju(V, edges);
    for (const auto& scc : sccs) {
        for (int vertex : scc) {
            cout << vertex << ' ';
        }
        cout << '\n';
    }
    return 0;
}
